bind.setValue:
function(e, v) {
  e.classList.remove('twh-callout-important', 'twh-callout-warning', 'twh-callout-introduction', 'twh-callout-example', 'twh-callout-extension');
  e.classList.add('twh-callout-' + v);
  const titles = {
    'important': '$string.ibcallout_important',
    'warning': '$string.ibcallout_warning',
    'introduction': '$string.ibcallout_introduction',
    'example': '$string.ibcallout_example',
    'extension': '$string.ibcallout_extension'
  };
  const icons = {
    'important': 'thumbtack',
    'warning': 'warning',
    'introduction': 'info-circle',
    'example': 'lightbulb-o',
    'extension': 'magnifying-glass-plus'
  };
  const titleElem = e.querySelector('.twh-callout-title');
  if (titleElem) {
    titleElem.textContent = titles[v];
  }
  const iconElem = e.querySelector('.twh-callout-icon i');
  if (iconElem) {
    iconElem.className = 'fa fa-' + icons[v];
  }
}
